function ChangePasswordModal({user,onClose,onSave}) {
  const [cur,setCur]=useState(""), [nw,setNw]=useState(""), [cf,setCf]=useState(""), [err,setErr]=useState(""), [ok,setOk]=useState(false);
  const submit = () => {
    if(cur!==user.password){setErr("Current password is incorrect.");return;}
    if(nw.length<6){setErr("New password must be at least 6 characters.");return;}
    if(nw!==cf){setErr("Passwords do not match.");return;}
    onSave(nw); setOk(true); setTimeout(onClose,1500);
  };
  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.55)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2000,padding:16}} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{background:"white",borderRadius:16,width:"100%",maxWidth:420,boxShadow:"0 24px 80px rgba(0,0,0,.28)"}}>
        <div style={{background:B,padding:"20px 24px",borderRadius:"16px 16px 0 0",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{color:"white",fontWeight:900,fontSize:18}}>Change Password</div>
          <button onClick={onClose} style={{background:"rgba(255,255,255,.2)",color:"white",border:"none",width:32,height:32,borderRadius:"50%",cursor:"pointer",fontSize:18}}>&#x2715;</button>
        </div>
        <div style={{padding:24}}>
          {ok ? (
            <div style={{textAlign:"center",padding:"20px 0"}}>
              <div style={{fontSize:48,marginBottom:12}}>&#x2705;</div>
              <div style={{fontWeight:800,color:"#1b5e20",fontSize:16}}>Password updated!</div>
            </div>
          ) : (
            <>
              <Inp label="Current Password" type="password" value={cur} onChange={e=>setCur(e.target.value)} placeholder="Your current password"/>
              <Inp label="New Password" type="password" value={nw} onChange={e=>setNw(e.target.value)} placeholder="At least 6 characters"/>
              <Inp label="Confirm New Password" type="password" value={cf} onChange={e=>setCf(e.target.value)} placeholder="Repeat new password"/>
              {err&&<div style={{background:"#fff0f0",color:C,border:"1px solid #ffd0cc",padding:"10px 14px",borderRadius:8,fontSize:13,marginBottom:14,fontWeight:600}}>{err}</div>}
              <div style={{display:"flex",gap:10}}>
                <button onClick={onClose} style={{flex:1,padding:"12px",background:"#f0f0f0",color:"#555",border:"none",borderRadius:8,fontSize:14,fontWeight:700,fontFamily:F,cursor:"pointer"}}>Cancel</button>
                <button onClick={submit} style={{flex:2,padding:"12px",background:B,color:"white",border:"none",borderRadius:8,fontSize:14,fontWeight:800,fontFamily:F,cursor:"pointer"}}>Update Password</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}

