                    <div style={{fontSize:11,opacity:.8}}>{room.sub}</div>
                    {room.approval&&<div style={{position:"absolute",top:14,right:14,background:"rgba(255,255,255,.22)",padding:"3px 10px",borderRadius:20,fontSize:9,fontWeight:800}}>APPROVAL REQ.</div>}
