                      <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                        {room.features.map(f=><span key={f} style={{background:room.col===C?"#fff0ef":room.col===D?"#eef3ff":"#eaf8ff",color:room.col,padding:"3px 10px",borderRadius:20,fontSize:11,fontWeight:600}}>{f}</span>)}
                      </div>
